{
  "activities": [
    {
      "type": "activity",
      "title": "Reading Comprehension Practice",
      "unit_name": "Reading Skills",
      "chapter_name": "Reading Skills",
      "details": "Students engage in reading discursive passages (400-450 words) and case-based factual passages with visual inputs to practice comprehension, interpretation, analysis, inference, evaluation, and vocabulary usage."
    },
    {
      "type": "activity",
      "title": "Grammar Accuracy Drill",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students practice gap-filling, editing, and transformation exercises focusing on Determiners, Tenses, Modals, Subject-verb concord, and Reported speech to ensure accuracy in spelling, punctuation, and grammar."
    },
    {
      "type": "activity",
      "title": "Descriptive Writing Workshop",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students write descriptive paragraphs (100-120 words) based on visual or verbal cues describing a person, event, or situation to develop creative expression and appropriate style."
    },
    {
      "type": "activity",
      "title": "Creative Storytelling Session",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Writing Skills and Grammar",
      "details": "Students compose a story based on a given cue/title or write a diary entry (100-120 words) to practice creative expression and fluency."
    },
    {
      "type": "activity",
      "title": "Literary Context Analysis",
      "unit_name": "Language through Literature",
      "chapter_name": "Reference to the Context",
      "details": "Students analyze extracts from Drama/Prose and Poetry, answering MCQs to assess interpretation, analysis, inference, evaluation, appreciation, and vocabulary."
    },
    {
      "type": "activity",
      "title": "Literature Discussion Circle",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students participate in peer interactions to answer short and long answer questions from Beehive and Moments, defending views and expressing ideas on themes, plots, and characters."
    },
    {
      "type": "activity",
      "title": "Role Play and Skit Performance",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students engage in role plays, skits, or dramatizations based on texts from Beehive and Moments to enhance listening and speaking skills."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Literary Project",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students create art-integrated projects based on activities like Role Play, Skit, or Dramatization derived from the prescribed texts (Beehive and Moments) to demonstrate understanding and creativity."
    }
  ],
  "practicals": [
    {
      "title": "Listening and Speaking Assessment",
      "unit_name": "Language through Literature",
      "chapter_name": "Short & Long Answer Questions",
      "details": "Students undergo assessment of Listening and Speaking Skills (05 marks) involving regular practice, interaction, and performance in activities like role play and group work."
    }
  ]
}
